import 'package:bloc/bloc.dart';import 'package:flower_e_commerce_app/Feature/mainLayout/tabs/profile/reset_password/domain/entities/request/reset_password_request_entity.dart';import 'package:flower_e_commerce_app/Feature/mainLayout/tabs/profile/reset_password/domain/entities/response/reset_password_response_entity.dart';import 'package:flower_e_commerce_app/Feature/mainLayout/tabs/profile/reset_password/domain/useCases/ResetPasswordUseCase.dart';import 'package:flower_e_commerce_app/Feature/mainLayout/tabs/profile/reset_password/presentation/viewModel/profile_event.dart';import 'package:flower_e_commerce_app/Feature/mainLayout/tabs/profile/reset_password/presentation/viewModel/reset_password_state.dart';import 'package:flower_e_commerce_app/core/Errors/api_results.dart';import 'package:flutter/material.dart';import 'package:injectable/injectable.dart';@injectableclass ResetPasswordViewModel extends Cubit<ResetPasswordState> {  final ResetPasswordUseCase _resetPasswordUseCase;  final TextEditingController currentPasswordController =      TextEditingController();  final TextEditingController newPasswordController = TextEditingController();  final TextEditingController confirmPasswordController = TextEditingController();  GlobalKey<FormState> resetPasswordFormKey = GlobalKey<FormState>();  ResetPasswordViewModel(this._resetPasswordUseCase)      : super(ResetPasswordState());  Future<void> doIntent(ResetPasswordEvent event) async {    switch (event) {      case ResetPasswordSubmitEvent():        await _resetPassword();    }  }  Future<void> _resetPassword() async {    emit(state.copyWith(isLoading: true, failure: null));    final resetPasswordRequestEntity = ResetPasswordRequestEntity(        currantPassword: currentPasswordController.text,        newPassword: newPasswordController.text);    final result =        await _resetPasswordUseCase.invoke(resetPasswordRequestEntity);    switch (result) {      case ApiSuccessResult<ResetPasswordResponseEntity>():        emit(state.copyWith(            isLoading: false, failure: null, resetPasswordSuccess: true));        break;      case ApiErrorResult<ResetPasswordResponseEntity>():        emit(state.copyWith(          isLoading: false,          failure: result.failure,          resetPasswordSuccess: false,        ));        break;    }  }}